blocks.body:
{
    "level": "A2–B1",
    "intro": "W tym temacie poznasz <strong>kolejność słów</strong> z czasownikami posiłkowymi, modalnymi i frazowymi: budowę zdania i zasady ustawiania dopełnień.",
    "rules": [
        {
            "label": "Posiłkowe",
            "color": "emerald",
            "text": "<strong>Podmiot + czasownik posiłkowy + czasownik główny + dopełnienie</strong>:",
            "example": "She is reading a book."
        },
        {
            "label": "Modalne",
            "color": "blue",
            "text": "<strong>Podmiot + czasownik modalny + czasownik w formie podstawowej + dopełnienie</strong> (bez to):",
            "example": "He can speak English."
        },
        {
            "label": "Phrasal Verbs",
            "color": "amber",
            "text": "Zaimek musi stać <strong>koniecznie</strong> między czasownikiem a partykułą:",
            "example": "Turn it off. (NIE: Turn off it.)"
        }
    ]
}

{
    "title": "1. Czasowniki posiłkowe (Auxiliary Verbs)",
    "intro": "Czasowniki posiłkowe be, do, have stoją przed czasownikiem głównym:",
    "items": [
        {
            "label": "Be",
            "title": "Continuous / strona bierna",
            "subtitle": "She is reading. / The book was written."
        },
        {
            "label": "Have",
            "title": "Czasy perfect",
            "subtitle": "They have finished. / He had left."
        },
        {
            "label": "Do",
            "title": "Pytania / przeczenia",
            "subtitle": "Do you know? / She doesn't like it."
        }
    ]
}

{
    "title": "2. Czasowniki modalne (Modal Verbs)",
    "sections": [
        {
            "label": "Budowa z modalnymi",
            "color": "emerald",
            "description": "Czasowniki modalne <strong>can, should, must, might, will, would</strong> stoją przed czasownikiem głównym (bez to).",
            "examples": [
                {
                    "en": "She can speak English.",
                    "ua": "Ona umie mówić po angielsku."
                },
                {
                    "en": "You should finish your homework.",
                    "ua": "Powinieneś skończyć pracę domową."
                },
                {
                    "en": "He must call the doctor.",
                    "ua": "On musi zadzwonić do lekarza."
                },
                {
                    "en": "They might arrive late.",
                    "ua": "Oni mogą przyjechać późno."
                }
            ]
        },
        {
            "label": "Przeczenia z modalnymi",
            "color": "sky",
            "description": "W przeczeniach <strong>not</strong> stawiamy po czasowniku modalnym.",
            "examples": [
                {
                    "en": "She cannot (can't) swim.",
                    "ua": "Ona nie umie pływać."
                },
                {
                    "en": "You should not (shouldn't) eat too much.",
                    "ua": "Nie powinieneś jeść za dużo."
                },
                {
                    "en": "He must not (mustn't) be late.",
                    "ua": "Nie wolno mu się spóźnić."
                }
            ],
            "note": "Po czasowniku modalnym zawsze występuje forma podstawowa: bez to i bez -s."
        }
    ]
}

{
    "title": "3. Czasowniki frazowe rozdzielne (Separable)",
    "sections": [
        {
            "label": "Dopełnienie rzeczownikowe",
            "color": "emerald",
            "description": "Dopełnienie rzeczownikowe może stać <strong>między</strong> czasownikiem a partykułą albo <strong>po</strong> całej konstrukcji.",
            "examples": [
                {
                    "en": "Turn off the light. = Turn the light off.",
                    "ua": "Wyłącz światło."
                },
                {
                    "en": "Pick up the package. = Pick the package up.",
                    "ua": "Podnieś paczkę."
                },
                {
                    "en": "Put on your coat. = Put your coat on.",
                    "ua": "Załóż płaszcz."
                }
            ]
        },
        {
            "label": "Dopełnienie zaimkowe",
            "color": "rose",
            "description": "Zaimek (it, him, her, them) musi stać <strong>koniecznie</strong> między czasownikiem a partykułą.",
            "examples": [
                {
                    "en": "Turn it off. ❌ Turn off it.",
                    "ua": "Wyłącz to."
                },
                {
                    "en": "Pick them up. ❌ Pick up them.",
                    "ua": "Podnieś je."
                },
                {
                    "en": "Put it on. ❌ Put on it.",
                    "ua": "Załóż to."
                }
            ],
            "note": "Ta zasada jest obowiązkowa. Zaimek nigdy nie stoi po partykule."
        }
    ]
}

{
    "title": "4. Czasowniki frazowe nierozdzielne (Inseparable)",
    "sections": [
        {
            "label": "Dopełnienie po phrasal verb",
            "color": "emerald",
            "description": "W <strong>nierozdzielnych</strong> phrasal verbs dopełnienie zawsze stoi <strong>po</strong> całej konstrukcji.",
            "examples": [
                {
                    "en": "Look after your dog.",
                    "ua": "Zaopiekuj się swoim psem."
                },
                {
                    "en": "She got over the illness.",
                    "ua": "Ona pokonała chorobę."
                },
                {
                    "en": "I came across an old photo.",
                    "ua": "Natknąłem się na stare zdjęcie."
                },
                {
                    "en": "He ran into an old friend.",
                    "ua": "Wpadł na starego przyjaciela."
                }
            ]
        },
        {
            "label": "Trzywyrazowe phrasal verbs",
            "color": "sky",
            "description": "Trzywyrazowe phrasal verbs są <strong>zawsze</strong> nierozdzielne.",
            "examples": [
                {
                    "en": "She can't put up with the noise.",
                    "ua": "Ona nie może znieść hałasu."
                },
                {
                    "en": "I'm looking forward to the trip.",
                    "ua": "Nie mogę się doczekać wyjazdu."
                },
                {
                    "en": "We've run out of milk.",
                    "ua": "Skończyło nam się mleko."
                }
            ]
        }
    ]
}

{
    "title": "5. Popularne phrasal verbs",
    "intro": "Zapamiętaj, które phrasal verbs są rozdzielne, a które nie:",
    "rows": [
        {
            "en": "turn on/off",
            "ua": "włączać / wyłączać",
            "note": "Rozdzielny"
        },
        {
            "en": "pick up",
            "ua": "podnieść, odebrać",
            "note": "Rozdzielny"
        },
        {
            "en": "put on",
            "ua": "założyć",
            "note": "Rozdzielny"
        },
        {
            "en": "throw away",
            "ua": "wyrzucić",
            "note": "Rozdzielny"
        },
        {
            "en": "look after",
            "ua": "opiekować się",
            "note": "Nierozdzielny"
        },
        {
            "en": "look for",
            "ua": "szukać",
            "note": "Nierozdzielny"
        },
        {
            "en": "get over",
            "ua": "dojść do siebie, pokonać",
            "note": "Nierozdzielny"
        }
    ],
    "warning": "📌 Jeśli nie masz pewności, sprawdź to w słowniku."
}

{
    "title": "6. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Zaimek po partykule zamiast między czasownikiem a partykułą.",
            "wrong": "Turn off it.",
            "right": "✅ <span class=\"font-mono\">Turn it off.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Czasownik modalny + to.",
            "wrong": "She can to swim.",
            "right": "✅ <span class=\"font-mono\">She can swim.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Rozdzielenie nierozdzielnego phrasal verb.",
            "wrong": "Look your dog after.",
            "right": "✅ <span class=\"font-mono\">Look after your dog.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Czasownik z -s po modalnym.",
            "wrong": "He must calls.",
            "right": "✅ <span class=\"font-mono\">He must call.</span>"
        }
    ]
}

{
    "title": "7. Krótkie podsumowanie",
    "items": [
        "Czasowniki posiłkowe (be, do, have): <strong>S + Aux + V + O</strong>.",
        "Modalne: <strong>S + Modal + Base Verb + O</strong> (bez to i bez -s).",
        "Rozdzielne phrasal verbs: dopełnienie może stać między czasownikiem a partykułą albo po całej konstrukcji.",
        "Zaimek w rozdzielnych phrasal verbs stoi <strong>koniecznie</strong> między czasownikiem a partykułą.",
        "Nierozdzielne i trzywyrazowe phrasal verbs: dopełnienie stoi <strong>po</strong> całej konstrukcji."
    ]
}

{
    "title": "8. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Wybierz poprawną opcję",
    "select_intro": "Wybierz zdanie z poprawnym szykiem wyrazów.",
    "selects": [
        {
            "label": "a) Turn it off. / b) Turn off it.",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) She can to swim. / b) She can swim.",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Look after the kids. / b) Look the kids after.",
            "prompt": "Która opcja jest poprawna?"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Ćwiczenie 2. Wstaw zaimek we właściwe miejsce",
    "input_intro": "Zastąp rzeczownik zaimkiem podanym w nawiasie.",
    "inputs": [
        {
            "before": "Pick up the book. (it)",
            "after": "→"
        },
        {
            "before": "Turn off the TV. (it)",
            "after": "→"
        },
        {
            "before": "Put on your shoes. (them)",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w szyku wyrazów.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "She must calls him.",
            "example_target": "She must call him."
        },
        {
            "original": "1. He can to play guitar.",
            "placeholder": "Popraw szyk wyrazów"
        },
        {
            "original": "2. Throw away them.",
            "placeholder": "Popraw szyk wyrazów"
        }
    ]
}

{
    "title": "Kontynuuj naukę",
    "items": [
        {
            "label": "Basic Word Order",
            "current": false
        },
        {
            "label": "Pytania i przeczenia",
            "current": false
        },
        {
            "label": "Word Order with Adverbs",
            "current": false
        },
        {
            "label": "Word Order with Verbs and Objects",
            "current": true
        },
        {
            "label": "Advanced Word Order",
            "current": false
        }
    ]
}
